function defaultLinkType(){const t=getUrlVars(window.location.href).a||localStorage.linktype||"link",e=document.querySelector(`.link-type li[data-label="${t}"]`),n=document.querySelector(".link-type input");e.classList.add("active"),n.value=t}function defaultEncoding(){const t=localStorage.encoding||"base64",e=document.querySelector('dropmenu[data-type="encoding"]'),n=e.querySelector("input"),o=e.querySelector(`li[data-option="${t}"]`);e.querySelector(".value").textContent=o.textContent,n.value=t,o.classList.add("active")}function defaultShortening(){const t=localStorage.shortening||"isgd",e=document.querySelector('dropmenu[data-type="shortening"]'),n=e.querySelector("input"),o=e.querySelector(`li[data-option="${t}"]`);e.querySelector(".value").textContent=o.textContent,n.value=t,o.classList.add("active")}function setDefaults(){try{defaultLinkType()}catch{}try{defaultEncoding()}catch{}try{defaultShortening()}catch{}}setDefaults();